/**
 * @author 纷享实施人员
 * @codeName 【计划任务】关联客户
 * @description 创建计划任务函数。查询银行流水对象日期据当前日期1个月内的全部数据，汇总打款金额，将汇总金额更新到客户对象上的近一个季度回款字段上。银行流水对象APIname：payment_record__c，银行流水的日期字段 API 名：date__c，银行流水的打款金额字段 API 名：transfer_amount__c，银行流水关联客户的字段 API 名：store_name__c，客户的近一个季度回款字段 API 名：quarterly_repayment__c
 * @createTime 2026-03-19
 * @bindingObjectLabel 银行流水
 * @bindingObjectApiName payment_record__c
 * @函数需求编号
 */
// ----- 1. 计算日期范围（当前日期前1个月） -----
long oneMonthAgo = System.currentTimeMillis() - (30L * 24 * 60 * 60 * 1000)
log.info("[业务] 入参: 查询日期范围 >= 1个月前")

// ----- 2. 查询银行流水（1个月内） -----
log.info("[业务] 查询银行流水对象，日期 >= 1个月前")
def (Boolean findErr, QueryResult findResult, String findMsg) = Fx.object.find(
    "payment_record__c",
    FQLAttribute.builder()
        .columns(["_id", "date__c", "transfer_amount__c", "store_name__c"])
        .queryTemplate(QueryTemplate.AND(["date__c": QueryOperator.GTE(oneMonthAgo)]))
        .build(),
    SelectAttribute.builder().build()
)

if (findErr) {
    log.error("[业务] 查询银行流水失败: " + findMsg)
    return
}

if (!findResult || !findResult.dataList || findResult.dataList.size() == 0) {
    log.info("[业务] 未查到符合条件的银行流水记录")
    return
}

log.info("[业务] 查到 " + findResult.dataList.size() + " 条银行流水记录")

// ----- 3. 按客户分组汇总打款金额 -----
Map<String, BigDecimal> customerAmountMap = [:]
findResult.dataList.each { Object flowObj ->
    Map flow = flowObj as Map
    String customerId = flow["store_name__c"] as String
    Object amountObj = flow["transfer_amount__c"]

    if (customerId && amountObj != null) {
        BigDecimal amount = new BigDecimal(amountObj.toString())
        BigDecimal current = customerAmountMap.get(customerId)
        if (current == null) {
            current = BigDecimal.ZERO
        }
        customerAmountMap.put(customerId, current.add(amount))
    }
}

log.info("[业务] 汇总完成，涉及 " + customerAmountMap.size() + " 个客户")

// ----- 4. 批量更新客户的近一个季度回款字段 -----
customerAmountMap.each { String customerId, BigDecimal totalAmount ->
    log.info("[业务] 更新客户 " + customerId + " 的回款金额: " + totalAmount)

    def (Boolean updateErr, Map updateResult, String updateMsg) = Fx.object.update(
        "AccountObj",
        customerId,
        ["quarterly_repayment__c": totalAmount] as Map<String, Object>,
        UpdateAttribute.builder().triggerWorkflow(false).build()
    )

    if (updateErr) {
        log.error("[业务] 更新客户 " + customerId + " 失败: " + updateMsg)
    } else {
        log.info("[业务] 更新客户 " + customerId + " 成功")
    }
}

log.info("[业务] 完成: 已更新所有客户的近一个季度回款")

/**
 * @author 纷享实施人员
 * @codeName 【流程】提货单更新
 * @description 生成一个流程函数。查询提货单上的门店名称，查询当前门店名称下的生命状态为正常的提货单，统计提货单上审核通过日期为3个月内的提货总额（元），汇总后更新至客户的近一个月回款字段内。
 * @createTime 2026-03-19
 * @bindingObjectLabel 提货单
 * @bindingObjectApiName DeliveryOrderObj
 * @函数需求编号
 */
// ----- 1. 取当前提货单数据 -----
String deliveryId = context.data._id as String
String storeId = context.data.account_id__c as String

log.info("[业务] 入参: deliveryId=" + (deliveryId ?: "空") + ", storeId=" + (storeId ?: "空"))

if (!deliveryId) {
    log.error("[业务] 终止: 提货单ID为空")
    return
}
if (!storeId) {
    log.error("[业务] 终止: 门店名称为空")
    return
}

// ----- 2. 查询门店下生命状态为正常的提货单 -----
log.info("[业务] 查询门店下生命状态为正常的提货单: storeId=" + storeId)
def (Boolean findErr, QueryResult findResult, String findMsg) = Fx.object.find(
    "DeliveryOrderObj",
    FQLAttribute.builder()
        .columns(["_id", "passing_date__c", "total_amount__c"])
        .queryTemplate(QueryTemplate.AND([
            "account_id__c": QueryOperator.EQ(storeId),
            "life_status": QueryOperator.EQ(1)
        ]))
        .build(),
    SelectAttribute.builder().build()
)

if (findErr) {
    log.error("[业务] 查询提货单失败: " + findMsg)
    return
}

if (!findResult || !findResult.dataList || findResult.dataList.size() == 0) {
    log.info("[业务] 未查到符合条件的提货单")
    return
}

// ----- 3. 统计3个月内提货总额 -----
long threeMonthsAgo = System.currentTimeMillis() - (90L * 24 * 60 * 60 * 1000)
BigDecimal totalAmount = BigDecimal.ZERO

List dataList = findResult.dataList as List
dataList.each { item ->
    Map itemMap = item as Map
    Object passingDateObj = itemMap.get("passing_date__c")
    Object amountObj = itemMap.get("total_amount__c")

    if (passingDateObj && amountObj) {
        long passingTime = 0L
        if (passingDateObj instanceof Long) {
            passingTime = passingDateObj as Long
        } else if (passingDateObj instanceof java.util.Date) {
            passingTime = (passingDateObj as java.util.Date).getTime()
        }

        if (passingTime >= threeMonthsAgo) {
            BigDecimal amount = BigDecimal.ZERO
            if (amountObj instanceof BigDecimal) {
                amount = amountObj as BigDecimal
            } else if (amountObj instanceof Number) {
                amount = new BigDecimal(amountObj.toString())
            }
            totalAmount = totalAmount.add(amount)
        }
    }
}

log.info("[业务] 统计完成: 3个月内提货总额=" + totalAmount.toString())

// ----- 4. 更新客户近一个月回款字段 -----
log.info("[业务] 更新客户字段: storeId=" + storeId + ", amount=" + totalAmount.toString())
def (Boolean updateErr, Map updateResult, String updateMsg) = Fx.object.update(
    "AccountObj",
    storeId,
    ["field_QiBJ2__c": totalAmount] as Map<String, Object>,
    UpdateAttribute.builder().triggerWorkflow(true).build()
)

if (updateErr) {
    log.error("[业务] 更新客户失败: " + updateMsg)
} else {
    log.info("[业务] 完成: 已更新客户近一个月回款")
}

