/**
 * @author 纷享实施人员
 * @codeName 【范围规则】客户的介绍人字段上增
 * @description 在客户的介绍人字段上增加范围规则函数。当当前客户的业务类型等于'门店'时，介绍人的范围规则仅能显示业务类型为'门店'的客户；当当前客户的业务类型等于'用户'时，介绍人的范围规则仅能显示业务类型为'用户'的客户；获取不到业务类型的情况下，显示全部类型的客户。
 * @createTime 2026-03-19
 * @bindingObjectLabel 客户
 * @bindingObjectApiName AccountObj
 * @函数需求编号
 */
// 待确认：以下选项值（'门店'、'用户'）需在平台「对象管理-客户-字段-客户分类-选项」中查看真实存储值并替换

String businessType = context.data.c_classification__c as String
if (!businessType) businessType = ""

if (businessType == "门店") {
    return [
        "searchCondition": QueryTemplate.AND([
            "c_classification__c": QueryOperator.EQ("门店")
        ])
    ]
}

if (businessType == "用户") {
    return [
        "searchCondition": QueryTemplate.AND([
            "c_classification__c": QueryOperator.EQ("用户")
        ])
    ]
}

return [:]
